<?php

declare(strict_types=1);
namespace App\Http\Controllers\Academic;
use App\Enums\DayOfWeek;use App\Http\Controllers\Controller;use App\Http\Requests\Academic\LessonScheduleRequest;use App\Models\{AcademicYear,Classroom,Employee,LessonSchedule,Semester,Subject,TeachingAssignment};use App\Services\Academic\ScheduleService;use Illuminate\Http\{RedirectResponse,Request,StreamedResponse};use Illuminate\View\View;
class ScheduleController extends Controller{public function index(Request $r):View{$q=LessonSchedule::with(['academicYear','semester','employee','classroom','subject','teachingAssignment'])->when($r->academic_year_id,fn($q,$v)=>$q->where('academic_year_id',$v))->when($r->semester_id,fn($q,$v)=>$q->where('semester_id',$v))->when($r->classroom_id,fn($q,$v)=>$q->where('classroom_id',$v))->when($r->employee_id,fn($q,$v)=>$q->where('employee_id',$v))->when($r->subject_id,fn($q,$v)=>$q->where('subject_id',$v))->when($r->day_of_week,fn($q,$v)=>$q->where('day_of_week',$v));$weekly=(clone $q)->orderBy('day_of_week')->orderBy('starts_at')->get()->groupBy(fn($s)=>$s->day_of_week->value);return view('schedules.index',$this->refs()+['schedules'=>$q->orderBy('day_of_week')->orderBy('starts_at')->paginate(15)->withQueryString(),'weekly'=>$weekly,'filters'=>$r->all()]);}public function create(Request $r):View{return view('schedules.form',$this->refs()+['schedule'=>new LessonSchedule,'selectedClassroom'=>$r->classroom_id]);}public function store(LessonScheduleRequest $r,ScheduleService $s):RedirectResponse{$sc=$s->save($r->validated()+['is_active'=>$r->boolean('is_active',true)]);return redirect()->route('schedules.show',$sc)->with('status','Jadwal Pelajaran berhasil disimpan.');}public function show(LessonSchedule $schedule):View{return view('schedules.show',['schedule'=>$schedule->load(['academicYear','semester','employee','classroom','subject','teachingAssignment'])]);}public function edit(LessonSchedule $schedule):View{return view('schedules.form',$this->refs()+['schedule'=>$schedule]);}public function update(LessonScheduleRequest $r,LessonSchedule $schedule,ScheduleService $s):RedirectResponse{$s->save($r->validated()+['is_active'=>$r->boolean('is_active')],$schedule);return redirect()->route('schedules.show',$schedule)->with('status','Jadwal Pelajaran diperbarui.');}public function toggle(LessonSchedule $schedule,ScheduleService $s):RedirectResponse{$s->toggle($schedule,!$schedule->is_active);return back()->with('status','Status jadwal diperbarui.');}public function destroy(LessonSchedule $schedule,ScheduleService $s):RedirectResponse{$s->toggle($schedule,false);return back()->with('status','Jadwal dinonaktifkan, bukan dihapus.');}public function print(Request $r):View{return view('schedules.print',$this->refs()+['items'=>LessonSchedule::with(['employee','classroom','subject','academicYear','semester'])->when($r->classroom_id,fn($q,$v)=>$q->where('classroom_id',$v))->when($r->employee_id,fn($q,$v)=>$q->where('employee_id',$v))->orderBy('day_of_week')->orderBy('starts_at')->get(),'printedAt'=>now()]);}public function export():StreamedResponse{$rows=LessonSchedule::with(['employee','classroom','subject','semester'])->get();return response()->streamDownload(function()use($rows){$f=fopen('php://output','w');fputcsv($f,['Hari','Jam','Kelas','Mata Pelajaran','Guru','Ruangan','Semester']);foreach($rows as $s)fputcsv($f,[$s->day_of_week?->label(),substr($s->starts_at,0,5).'-'.substr($s->ends_at,0,5),$s->classroom?->name,$s->subject?->name,$s->employee?->name,$s->room,$s->semester?->name]);},'jadwal-pelajaran.csv',['Content-Type'=>'text/csv']);}private function refs():array{return['academicYears'=>AcademicYear::all(),'semesters'=>Semester::all(),'classrooms'=>Classroom::where('is_active',true)->get(),'employees'=>Employee::where('is_active',true)->get(),'subjects'=>Subject::where('is_active',true)->get(),'assignments'=>TeachingAssignment::with(['employee','classroom','subject','semester'])->where('is_active',true)->get(),'days'=>DayOfWeek::cases()];}}
